// src/components/Navbar.jsx

import { FaHome, FaSignOutAlt } from "react-icons/fa";

export default function Navbar() {

  const logout = () => {
    localStorage.removeItem("user");
    window.location = "/";
  };

  return (
    <div style={styles.navbar}>

      {/* LOGO */}
      <div style={styles.logoBox}>

        <div style={styles.logoCircle}>
          D
        </div>

        <h2 style={styles.logoText}>
          DailyMajdoor
        </h2>

      </div>

      {/* MENU */}
      <div style={styles.menu}>

        <button
          style={styles.homeBtn}
          onClick={() => window.location = "/"}
        >
          <FaHome />
          Home
        </button>

        <button
          style={styles.logoutBtn}
          onClick={logout}
        >
          <FaSignOutAlt />
          Logout
        </button>

      </div>

    </div>
  );
}

const styles = {

  navbar: {
    height: "80px",
    background: "rgba(15,23,42,0.95)",
    backdropFilter: "blur(12px)",
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    padding: "0 60px",
    borderBottom: "1px solid rgba(255,255,255,0.08)",
    position: "sticky",
    top: 0,
    zIndex: 1000,
    boxShadow: "0 10px 30px rgba(0,0,0,0.25)"
  },

  logoBox: {
    display: "flex",
    alignItems: "center",
    gap: "14px"
  },

  logoCircle: {
    width: "44px",
    height: "44px",
    borderRadius: "14px",
    background: "linear-gradient(135deg,#f97316,#fb923c)",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    color: "white",
    fontWeight: "bold",
    fontSize: "18px",
    boxShadow: "0 8px 20px rgba(249,115,22,0.4)"
  },

  logoText: {
    fontSize: "24px",
    color: "white",
    margin: 0,
    fontWeight: "700",
    letterSpacing: "0.5px"
  },

  menu: {
    display: "flex",
    gap: "16px"
  },

  homeBtn: {
    display: "flex",
    alignItems: "center",
    gap: "8px",
    background: "rgba(255,255,255,0.08)",
    border: "1px solid rgba(255,255,255,0.08)",
    padding: "12px 22px",
    borderRadius: "12px",
    color: "white",
    cursor: "pointer",
    fontWeight: "600",
    fontSize: "14px",
    transition: "0.3s",
    backdropFilter: "blur(10px)"
  },

  logoutBtn: {
    display: "flex",
    alignItems: "center",
    gap: "8px",
    background: "linear-gradient(135deg,#f97316,#fb923c)",
    color: "white",
    border: "none",
    padding: "12px 22px",
    borderRadius: "12px",
    cursor: "pointer",
    fontWeight: "600",
    fontSize: "14px",
    boxShadow: "0 8px 25px rgba(249,115,22,0.35)",
    transition: "0.3s"
  }

};
